template <std::size_t N>
void expect_pool(const RunState& rs, RelicPool pool,
                 const std::array<RelicId, N>& expected) {
    const int p = static_cast<int>(pool);
    ASSERT_EQ(rs.relic_pool_count[p], N);
    for (std::size_t i = 0; i < N; ++i) {
        EXPECT_EQ(rs.relic_pools[p][i], static_cast<uint16_t>(expected[i]))
            << "pool index " << i;
    }
}

template <std::size_t N>
void set_pool(RunState& rs, RelicPool pool,
              const std::array<RelicId, N>& ids) {
    const int p = static_cast<int>(pool);
    rs.relic_pool_count[p] = static_cast<uint8_t>(N);
    for (std::size_t i = 0; i < N; ++i) {
        rs.relic_pools[p][i] = static_cast<uint16_t>(ids[i]);
    }
}

