TEST(RelicPools, OracleCommonPoolOrdersMatchThreeLiveSeeds) {
    struct Case {
        int64_t seed;
        const std::array<RelicId, 33>* pool;
        int64_t s0;
        int64_t s1;
    };
    const Case cases[] = {
        {1790050543751LL, &kOracleSeed1, -6368056192266778531LL,
         -2945499761529171947LL},
        {1790050543752LL, &kOracleSeed2, -2647188671728073487LL,
         -7059635356477542313LL},
        {1790050543753LL, &kOracleSeed3, 5762858951679628331LL,
         -7642149939435051131LL},
    };
    for (const Case& c : cases) {
        RunState rs{};
        rs.relic_rng = from_seed(c.seed);
        initialize_relic_pools(rs);
        // B4.6's pinned oracle values, UNCHANGED by B3.25: the common shuffle
        // consumes relicRng draw #1 and the post-five-draw stream state is
        // independent of tier contents (all five draws are unconditional).
        expect_pool(rs, RelicPool::COMMON, *c.pool);
        EXPECT_EQ(rs.relic_rng.counter, 5);
        EXPECT_EQ(rs.relic_rng.s0, static_cast<uint64_t>(c.s0));
        EXPECT_EQ(rs.relic_rng.s1, static_cast<uint64_t>(c.s1));
        for (int p = 2; p < kRelicTierCount; ++p) {
            EXPECT_EQ(rs.relic_pool_count[p], 0)
                << "tier content belongs to B3.26-B3.27, p=" << p;
        }
    }
}

TEST(RelicPools, OracleUncommonPoolOrdersMatchThreeLiveSeeds) {
    struct Case {
        int64_t seed;
        const std::array<RelicId, 30>* pool;
    };
    const Case cases[] = {
        {1790050543751LL, &kOracleUncommonSeed1},
        {1790050543752LL, &kOracleUncommonSeed2},
        {1790050543753LL, &kOracleUncommonSeed3},
    };
    for (const Case& c : cases) {
        RunState rs{};
        rs.relic_rng = from_seed(c.seed);
        initialize_relic_pools(rs);
        expect_pool(rs, RelicPool::UNCOMMON, *c.pool);
        EXPECT_EQ(rs.relic_rng.counter, 5);
    }
}

TEST(RelicPools, InitializesAllFiveWithFiveDrawsEvenWhenFourAreEmpty) {
    RunState rs{};
    rs.relic_rng = from_seed(77);
    RngStream expected = rs.relic_rng;
    for (int i = 0; i < 5; ++i) {
        (void)random_long(expected);
    }
    initialize_relic_pools(rs);
    EXPECT_EQ(rs.relic_pool_count[kCommon], 33);
    EXPECT_EQ(rs.relic_rng.counter, 5);
    EXPECT_EQ(rs.relic_rng.s0, expected.s0);
    EXPECT_EQ(rs.relic_rng.s1, expected.s1);
}

TEST(RelicPools, Trap15FrontVsEndPopOppositeSides) {
    constexpr std::array ids{RelicId::ANCHOR, RelicId::BLOOD_VIAL,
                             RelicId::VAJRA};
    RunState front{};
    RunState end{};
    set_pool(front, RelicPool::COMMON, ids);
    set_pool(end, RelicPool::COMMON, ids);
    EXPECT_EQ(return_random_relic_key(front, RelicTier::COMMON), RelicId::ANCHOR);
    EXPECT_EQ(return_end_random_relic_key(end, RelicTier::COMMON), RelicId::VAJRA);
    EXPECT_EQ(front.relic_pool_count[kCommon], 2);
    EXPECT_EQ(end.relic_pool_count[kCommon], 2);
}

